// Parse incoming payload from Supabase generate-social-content function
// Split content items into:
//   - video_items: tiktok, instagram, youtube, facebook (need voiceover + video)
//   - text_items: pinterest, linkedin (text/image posts only)

const payload = $input.first().json.body || $input.first().json;

const videoItems = (payload.content_items || []).filter(item =>
  ['tiktok', 'instagram', 'youtube', 'facebook'].includes(item.platform)
);

const textItems = (payload.content_items || []).filter(item =>
  ['pinterest', 'linkedin'].includes(item.platform)
);

// Use first video item's script for voiceover (all video platforms share same script)
const primaryVideoItem = videoItems[0] || {};

return [{
  json: {
    run_date: payload.run_date,
    content_angle: payload.content_angle,
    pexels_query: payload.pexels_query || 'fitness workout health',
    voice_gender: payload.voice_gender || 'female',
    script: payload.script || primaryVideoItem.script || '',
    video_items: videoItems,
    text_items: textItems,
    all_items: payload.content_items || [],
  }
}];

// Build the audio public URL from Supabase Storage
// IMPORTANT: Must match exact URL pattern used by Upload Audio to Supabase Storage node

const supabaseUrl = 'https://mxggxpoxgqubojvumjlt.supabase.co';
const bucketName = 'yfit-voiceovers';

const parseData = $('Parse Supabase Payload').first().json;
const runDate = parseData.run_date || new Date().toISOString().split('T')[0];
const rawAngle = parseData.content_angle || 'workout';

// Use EXACT same sanitization as Upload Audio node:
// .replace(/[^a-z0-9\-]/gi, '_').substring(0, 80)
const sanitizedAngle = rawAngle.replace(/[^a-z0-9\-]/gi, '_').substring(0, 80);

// Build the public URL - no extra encoding needed since the filename is already sanitized
const audioUrl = `${supabaseUrl}/storage/v1/object/public/${bucketName}/voiceovers/${runDate}_${sanitizedAngle}.mp3`;

console.log('Audio URL:', audioUrl);

// Get first video item for caption text
const firstVideoItem = (parseData.video_items || [])[0] || {};
const captionText = ((firstVideoItem.caption || parseData.script || '').split('\n')[0]).substring(0, 60);

return [{
  json: {
    ...parseData,
    voiceover_url: audioUrl,
    caption_text: captionText,
    video_items: parseData.video_items,
    text_items: parseData.text_items,
  }
}];

// Check if video assembly succeeded
const result = $input.first().json;

if (!result.success || !result.video_url) {
  throw new Error('Video assembly failed: ' + (result.error || 'No video URL returned'));
}

const parseData = $('Parse Supabase Payload').first().json;

// Return one item per video platform
return parseData.video_items.map(item => ({
  json: {
    platform: item.platform,
    video_url: result.video_url,
    caption: item.caption || '',
    title: item.script ? item.script.substring(0, 100) : 'YFIT Fitness Tip',
    hashtags: item.hashtags || [],
    content_angle: parseData.content_angle,
    run_date: parseData.run_date,
  }
}));

// Handle Pinterest and LinkedIn text posts
// These don't need video — just text + hashtags via Upload-Post

const parseData = $('Parse Supabase Payload').first().json;
return (parseData.text_items || []).map(item => ({
  json: {
    platform: item.platform,
    caption: item.caption || item.script || '',
    hashtags: (item.hashtags || []).join(' '),
  }
}));

// Collect results from both video and text posting branches
// Log summary to console

const videoResult = $input.first().json;
console.log('Post result:', JSON.stringify(videoResult));

return [{
  json: {
    success: true,
    posted_at: new Date().toISOString(),
    result: videoResult,
  }
}];

// YFIT Social Media — Test Data
// Edit this to change what gets tested.
// This simulates what Supabase normally sends to the webhook.

return [{
  json: {
    run_date: new Date().toISOString().split('T')[0],
    content_angle: 'Test: 3 quick tips to boost your morning workout energy',
    pexels_query: 'fitness workout morning',
    voice_gender: 'female',
    script: 'Here are 3 quick tips to boost your morning workout energy. Number one: hydrate immediately after waking up. Number two: do a 5-minute dynamic warm-up. Number three: eat a light protein snack 30 minutes before training.',
    dry_run: true,  // Set to false to actually post to social media
    content_items: [
      {
        platform: 'tiktok',
        script: 'Here are 3 quick tips to boost your morning workout energy. Hydrate, warm up, and fuel up!',
        caption: '3 morning workout tips that actually work 💪 #fitness #morningworkout #yfitai',
        hashtags: ['#fitness', '#morningworkout', '#yfitai', '#healthylifestyle']
      },
      {
        platform: 'instagram',
        script: 'Here are 3 quick tips to boost your morning workout energy.',
        caption: 'Start your morning right 🌅 These 3 tips will transform your workout energy. Save this post! #YFIT #FitnessMotivation',
        hashtags: ['#YFIT', '#FitnessMotivation', '#MorningWorkout']
      },
      {
        platform: 'linkedin',
        title: '3 Science-Backed Tips to Maximize Morning Workout Performance',
        body: 'Morning workouts are proven to boost productivity and mood throughout the day. Here are 3 evidence-based strategies: 1) Hydration first — drink 500ml of water immediately upon waking. 2) Dynamic warm-up — 5 minutes of movement prep reduces injury risk by 40%. 3) Pre-workout nutrition — a light protein snack 30 min before training improves performance by up to 20%. Try these tomorrow and track the difference. #Fitness #Wellness #YFIT'
      },
      {
        platform: 'pinterest',
        title: '3 Morning Workout Energy Tips',
        description: 'Boost your morning workout with these 3 simple tips: hydrate, warm up dynamically, and eat a light protein snack. Save this pin for your fitness routine!',
        board: 'Fitness Tips'
      }
    ]
  }
}];

// Dry Run Logger — summarizes what would have been posted
const items = $input.all();

const report = {
  dry_run: true,
  timestamp: new Date().toISOString(),
  total_platforms: items.length,
  summary: items.map(item => ({
    platform: item.json.platform,
    content_type: item.json.content_type,
    caption_preview: (item.json.caption || item.json.body || '').substring(0, 120) + '...',
    hashtags: item.json.hashtags || [],
    status: 'WOULD_POST'
  }))
};

console.log('\n=== DRY RUN COMPLETE ===');
console.log(JSON.stringify(report, null, 2));
console.log('\nTo run for real: set dry_run: false in the Test Data node');

return [{ json: report }];

// Dry Run Logger (Text Posts)
const items = $input.all();

const report = {
  dry_run: true,
  post_type: 'text',
  timestamp: new Date().toISOString(),
  total_platforms: items.length,
  summary: items.map(item => ({
    platform: item.json.platform,
    title: item.json.title || '(no title)',
    body_preview: (item.json.body || item.json.description || item.json.caption || '').substring(0, 150) + '...',
    status: 'WOULD_POST'
  }))
};

console.log('\n=== DRY RUN — TEXT POSTS ===');
console.log(JSON.stringify(report, null, 2));

return [{ json: report }];

// Rename binary field to 'data' for the Upload node
const item = $input.first();
const binaryData = item.binary || {};
const binaryKeys = Object.keys(binaryData);
console.log('Binary fields from ElevenLabs:', binaryKeys);

if (binaryKeys.length === 0) {
  throw new Error('No binary audio data received from ElevenLabs');
}

// Get the first binary field (whatever name ElevenLabs gave it)
const firstKey = binaryKeys[0];
const audioData = binaryData[firstKey];
console.log('Audio field:', firstKey, '- mimeType:', audioData.mimeType);

// Return with field explicitly named 'data'
return [{
  json: item.json,
  binary: {
    data: {
      ...audioData,
      mimeType: 'audio/mpeg',
      fileExtension: 'mp3'
    }
  }
}];

